class DependencyTool(Enum):
    """Supported dependency management tools."""
    PIP_TOOLS = "pip-tools"
    POETRY = "poetry"
    PIPENV = "pipenv"
    RAW_PIP = "raw-pip"


class Environment(Enum):
    """Deployment environments with separate dependency sets."""
    PRODUCTION = "production"
    DEVELOPMENT = "development"
    TEST = "test"
    CI = "ci"


@dataclass
class DependencySpec:
    """Represents a single dependency specification."""
    name: str
    version: str
    hashes: List[str] = field(default_factory=list)
    extras: List[str] = field(default_factory=list)
    markers: Optional[str] = None
    source: Optional[str] = None
    is_direct: bool = True

    def to_pip_line(self, include_hashes: bool = True) -> str:
        """Convert to pip requirements.txt format."""
        extras_str = f"[{','.join(self.extras)}]" if self.extras else ""
        line = f"{self.name}{extras_str}=={self.version}"
        if self.markers:
            line += f" ; {self.markers}"
        if include_hashes and self.hashes:
            for h in self.hashes:
                line += f" \\\n    --hash={h}"
        return line

    def __str__(self) -> str:
        return f"{self.name}=={self.version}"


