@dataclass
class ProjectConfig:
    """Project-level dependency management configuration."""
    project_root: Path
    tool: DependencyTool = DependencyTool.PIP_TOOLS
    python_version: str = ""
    use_hashes: bool = True
    environments: List[Environment] = field(
        default_factory=lambda: [Environment.PRODUCTION, Environment.DEVELOPMENT, Environment.TEST]
    )
    index_url: str = "https://pypi.org/simple/"
    extra_index_urls: List[str] = field(default_factory=list)
    trusted_hosts: List[str] = field(default_factory=list)
    allow_prereleases: bool = False
    generate_hashes: bool = True

    # File paths relative to project root
    input_files: Dict[str, str] = field(default_factory=lambda: {
        "production": "requirements/production.in",
        "development": "requirements/development.in",
        "test": "requirements/test.in",
    })
    output_files: Dict[str, str] = field(default_factory=lambda: {
        "production": "requirements/production.txt",
        "development": "requirements/development.txt",
        "test": "requirements/test.txt",
    })
    metadata_file: str = "requirements/.lock-metadata.json"

    def __post_init__(self):
        if not self.python_version:
            self.python_version = f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}"


