class BaseLockFileGenerator:
    """Base class for lock file generators."""

    def __init__(self, config: ProjectConfig):
        self.config = config

    def generate(self, environment: str) -> bool:
        raise NotImplementedError

    def install(self, environment: str) -> bool:
        raise NotImplementedError

    def check_tool_available(self) -> bool:
        raise NotImplementedError

    def _run_command(
        self, cmd: List[str], capture_output: bool = True, check: bool = True
    ) -> subprocess.CompletedProcess:
        """Run a shell command with proper error handling."""
        logger.debug(f"Running command: {' '.join(cmd)}")
        try:
            result = subprocess.run(
                cmd,
                capture_output=capture_output,
                text=True,
                check=check,
                cwd=str(self.config.project_root),
            )
            return result
        except subprocess.CalledProcessError as e:
            logger.error(f"Command failed: {' '.join(cmd)}")
            logger.error(f"STDOUT: {e.stdout}")
            logger.error(f"STDERR: {e.stderr}")
            raise
        except FileNotFoundError:
            logger.error(f"Command not found: {cmd[0]}")
            raise


class PipToolsGenerator(BaseLockFileGenerator):
    """
    Generate lock files using pip-tools (pip-compile / pip-sync).

    pip-tools is the recommended approach for projects using requirements.txt.
    It provides:
    - Deterministic builds with pinned versions
    - Hash checking for security
    - Layered requirements (dev inherits from prod)
    - Clear separation of direct vs transitive dependencies

    Directory Structure:
        requirements/
        ├── production.in          # Direct production dependencies
        ├── production.txt         # Locked production dependencies (generated)
        ├── development.in         # Direct development dependencies
        ├── development.txt        # Locked development dependencies (generated)
        ├── test.in                # Direct test dependencies
        ├── test.txt               # Locked test dependencies (generated)
        └── .lock-metadata.json    # Lock file metadata (generated)
    """

    def check_tool_available(self) -> bool:
        """Check if pip-tools is installed."""
        try:
            self._run_command([sys.executable, "-m", "piptools", "--version"])
            return True
        except (subprocess.CalledProcessError, FileNotFoundError):
            return False

    def install_tool(self) -> bool:
        """Install pip-tools if not available."""
        logger.info("Installing pip-tools...")
        try:
            self._run_command(
                [sys.executable, "-m", "pip", "install", "pip-tools>=7.0.0"]
            )
            return True
        except subprocess.CalledProcessError:
            logger.error("Failed to install pip-tools")
            return False

    def generate(self, environment: str) -> bool:
        """
        Generate a locked requirements file for the specified environment.

        This runs pip-compile to resolve all dependencies and pin exact versions.
        If hash generation is enabled, it also computes and includes SHA256 hashes
        for every package.
        """
        input_file = self.config.project_root / self.config.input_files.get(
            environment, f"requirements/{environment}.in"
        )
        output_file = self.config.project_root / self.config.output_files.get(
            environment, f"requirements/{environment}.txt"
        )

        if not input_file.exists():
            logger.error(f"Input file not found: {input_file}")
            return False

        # Ensure output directory exists
        output_file.parent.mkdir(parents=True, exist_ok=True)

        # Build pip-compile command
        cmd = [
            sys.executable, "-m", "piptools", "compile",
            "--output-file", str(output_file),
            "--strip-extras",
            "--no-header",
            "--annotation-style", "line",
            "--resolver", "backtracking",
        ]

        if self.config.generate_hashes:
            cmd.append("--generate-hashes")

        if self.config.allow_prereleases:
            cmd.append("--pre")

        if self.config.index_url != "https://pypi.org/simple/":
            cmd.extend(["--index-url", self.config.index_url])

        for extra_url in self.config.extra_index_urls:
            cmd.extend(["--extra-index-url", extra_url])

        for host in self.config.trusted_hosts:
            cmd.extend(["--trusted-host", host])

        cmd.append(str(input_file))

        logger.info(f"Generating lock file for '{environment}' environment...")
        logger.info(f"  Input:  {input_file}")
        logger.info(f"  Output: {output_file}")

        try:
            self._run_command(cmd)
            self._add_header(output_file, environment)
            logger.info(f"Successfully generated: {output_file}")
            return True
        except subprocess.CalledProcessError:
            logger.error(f"Failed to generate lock file for '{environment}'")
            return False

    def _add_header(self, output_file: Path, environment: str) -> None:
        """Add a descriptive header to the generated lock file."""
        header = f"""\
#
# LOCKED DEPENDENCIES - DO NOT EDIT MANUALLY
#
# This file is auto-generated by the dependency manager using pip-tools.
# To update dependencies, modify the corresponding .in file and run:
#
#   python dependency_manager.py lock --env {environment}
#
# Environment: {environment}
# Generated:   {datetime.now().isoformat()}
# Python:      {self.config.python_version}
#
"""
        content = output_file.read_text()
        output_file.write_text(header + content)

    def install(self, environment: str) -> bool:
        """
        Install dependencies from a locked requirements file.

        Uses pip-sync for production to ensure the environment exactly matches
        the lock file (removing packages not in the lock file).
        Uses pip install for development to be less destructive.
        """
        output_file = self.config.project_root / self.config.output_files.get(
            environment, f"requirements/{environment}.txt"
        )

        if not output_file.exists():
            logger.error(f"Lock file not found: {output_file}. Run 'lock' first.")
            return False

        if environment == "production":
            # Use pip-sync for production - ensures exact match
            cmd = [
                sys.executable, "-m", "piptools", "sync",
                str(output_file),
            ]
            logger.info(f"Syncing {environment} environment (pip-sync)...")
        else:
            # For dev/test, use pip install to be less destructive
            cmd = [
                sys.executable, "-m", "pip", "install",
                "-r", str(output_file),
            ]
            if self.config.generate_hashes:
                cmd.append("--require-hashes")
            logger.info(f"Installing {environment} dependencies (pip install)...")

        try:
            self._run_command(cmd)
            logger.info(f"Successfully installed {environment} dependencies")
            return True
        except subprocess.CalledProcessError:
            logger.error(f"Failed to install {environment} dependencies")
            return False

    def update_package(self, package_name: str, environment: str) -> bool:
        """Update a specific package in the lock file."""
        input_file = self.config.project_root / self.config.input_files.get(
            environment, f"requirements/{environment}.in"
        )
        output_file = self.config.project_root / self.config.output_files.get(
            environment, f"requirements/{environment}.txt"
        )

        if not input_file.exists():
            logger.error(f"Input file not found: {input_file}")
            return False

        cmd = [
            sys.executable, "-m", "piptools", "compile",
            "--output-file", str(output_file),
            "--strip-extras",
            "--no-header",
            "--annotation-style", "line",
            "--resolver", "backtracking",
            "--upgrade-package", package_name,
        ]

        if self.config.generate_hashes:
            cmd.append("--generate-hashes")

        cmd.append(str(input_file))

        logger.info(f"Updating '{package_name}' in {environment} lock file...")
        try:
            self._run_command(cmd)
            self._add_header(output_file, environment)
            logger.info(f"Successfully updated '{package_name}'")
            return True
        except subprocess.CalledProcessError:
            logger.error(f"Failed to update '{package_name}'")
            return False


